import{_ as d,o as e,c as a,a4 as r}from"./chunks/framework.4M7SpZrd.js";const u=JSON.parse('{"title":"Motores de Deteccao","description":"","frontmatter":{},"headers":[],"relativePath":"motores/overview.md","filePath":"motores/overview.md"}'),o={name:"motores/overview.md"};function i(c,t,s,n,l,h){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="motores-de-deteccao" tabindex="-1">Motores de Deteccao <a class="header-anchor" href="#motores-de-deteccao" aria-label="Permalink to &quot;Motores de Deteccao&quot;">​</a></h1><p>O Kubex opera com <strong>27 motores de deteccao</strong> + <strong>5 utilitarios de performance</strong> que cobrem busca por imagem, monitoramento de redes sociais, reconhecimento facial, watermarking, takedown automatizado, descoberta autonoma de sites pirata, protecao NCII, OCR, deteccao de deepfake, classificacao NSFW, analise forense e quality gates.</p><p>Para resiliencia e anti-bloqueio, veja <a href="./resiliencia">Resiliencia dos Motores</a>. Para paginacao, veja <a href="./paginacao">Paginacao</a>.</p><hr><h2 id="tabela-resumo" tabindex="-1">Tabela Resumo <a class="header-anchor" href="#tabela-resumo" aria-label="Permalink to &quot;Tabela Resumo&quot;">​</a></h2><p>Todos os 27 motores + 5 utilitarios de performance estao implementados e ativos.</p><table tabindex="0"><thead><tr><th>Motor</th><th>Nome</th><th>Tipo</th><th>API/Key</th><th>Queue Celery</th><th>Storage</th><th>Status</th></tr></thead><tbody><tr><td><a href="./motor-01-api-search">01</a></td><td>Lens — Busca por Imagem</td><td>API externa + cascade</td><td>SerpAPI Google Lens</td><td>default</td><td>SearchResult</td><td>Ativo</td></tr><tr><td><a href="./motor-02-web-crawler">02</a></td><td>Crawler — Web Crawler</td><td>Scraper (Scrapling)</td><td>Nenhuma</td><td>default</td><td>SearchResult</td><td>Ativo</td></tr><tr><td><a href="./motor-03-perceptual-hash">03</a></td><td>Fingerprint — Perceptual Hash</td><td>Algoritmo local</td><td>Nenhuma</td><td>—</td><td>ContentHash</td><td>Ativo</td></tr><tr><td><a href="./motor-04-name-search">04</a></td><td>BrandWatch — Busca por Nome</td><td>Hibrido (API + crawler)</td><td>SerpAPI</td><td>default</td><td>SearchResult</td><td>Ativo</td></tr><tr><td><a href="./motor-05-telegram">05</a></td><td>Telegram Monitor</td><td>MTProto client</td><td>TELEGRAM_API_ID/HASH</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-06-face-recognition">06</a></td><td>FaceID — Reconhecimento Facial</td><td>InsightFace + Milvus</td><td>Nenhuma</td><td>celery_face</td><td>CreatorEmbedding</td><td>Ativo</td></tr><tr><td><a href="./motor-07-takedown">07</a></td><td>Takedown</td><td>Template + WHOIS</td><td>Nenhuma</td><td>—</td><td>Takedown</td><td>Ativo</td></tr><tr><td><a href="./motor-08-alert-system">08</a></td><td>Orchestrator — Alert System</td><td>Orquestrador</td><td>Nenhuma</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-09-discord">09</a></td><td>Discord Monitor</td><td>REST API</td><td>DISCORD_BOT_TOKEN</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-10-watermark">10</a></td><td>Watermark — Steganografia</td><td>Steganografia</td><td>Nenhuma</td><td>—</td><td>WatermarkedContent</td><td>Ativo</td></tr><tr><td><a href="./motor-11-video-fingerprint">11</a></td><td>VideoPrint — Video Fingerprint</td><td>ffmpeg + pHash</td><td>Nenhuma</td><td>celery_video</td><td>VideoContentHash</td><td>Ativo</td></tr><tr><td><a href="./motor-12-clip-ai">12</a></td><td>SemanticAI — CLIP AI</td><td>Vision-Language AI</td><td>Nenhuma</td><td>default</td><td>ContentHash</td><td>Ativo</td></tr><tr><td><a href="./motor-13-reddit">13</a></td><td>Reddit Monitor</td><td>OAuth2 API</td><td>REDDIT_CLIENT_ID/SECRET</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-14-google-alerts">14</a></td><td>AlertsFeed — Google Alerts</td><td>RSS parsing</td><td>Nenhuma</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-15-twitter">15</a></td><td>X Monitor — Twitter/X</td><td>X API v2</td><td>TWITTER_BEARER_TOKEN</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-16-darkweb">16</a></td><td>DarkWeb Monitor</td><td>Tor SOCKS5</td><td>TOR_SOCKS5_PROXY</td><td>—</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-17-source-discovery">17</a></td><td>SourceIntel — Descoberta de Fontes</td><td>Hibrido (cross-ref + search)</td><td>Nenhuma</td><td>default</td><td>DiscoveredSource</td><td>Ativo</td></tr><tr><td><a href="./motor-18-instagram">18</a></td><td>Instagram Monitor</td><td>Instaloader (scraping)</td><td>INSTAGRAM_MONITOR_ENABLED</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-19-marketplace">19</a></td><td>Marketplace Monitor</td><td>Scraper + API</td><td>Nenhuma</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-20-ocr">20</a></td><td>OCR — Texto em Imagem</td><td>Tesseract OCR</td><td>Nenhuma</td><td>—</td><td>OcrResult</td><td>Ativo</td></tr><tr><td><a href="./motor-21-deepfake">21</a></td><td>DeepGuard — Deepfake Detection</td><td>DCT + Boundary + EfficientNet</td><td>Nenhuma</td><td>celery_face</td><td>DeepfakeResult</td><td>Ativo</td></tr><tr><td><a href="./motor-22-facebook">22</a></td><td>Facebook Monitor</td><td>Graph API + scraping</td><td>FACEBOOK_API_KEY</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-23-flickr">23</a></td><td>Flickr Monitor</td><td>Flickr API</td><td>FLICKR_API_KEY</td><td>default</td><td>Alert</td><td>Ativo</td></tr><tr><td><a href="./motor-24-auto-discovery">24</a></td><td>AutoDiscovery — 100% Autonomo</td><td>OSINT + SerpAPI Dorks</td><td>SERPAPI_API_KEY</td><td>celery_low</td><td>DiscoveryTarget</td><td>Ativo</td></tr><tr><td><a href="./motor-25-shieldai">25</a></td><td>ShieldAI — Protecao NCII</td><td>Browser automation + anti-bloqueio</td><td>SHIELD_API_KEY</td><td>celery_low</td><td>CrawlerResult</td><td>Ativo</td></tr><tr><td><a href="./motor-26-nsfw">26</a></td><td>NSFW Classifier</td><td>MobileNet v2 ONNX</td><td>Nenhuma</td><td>celery_ai</td><td>JSONB scores</td><td>Ativo</td></tr><tr><td><a href="./motor-27-sentinel">27</a></td><td>Sentinel — Self-Healing</td><td>Health monitoring + auto-recovery</td><td>Nenhuma</td><td>default</td><td>SystemMetric</td><td>Ativo</td></tr></tbody></table><h3 id="utilitarios-de-performance" tabindex="-1">Utilitarios de Performance <a class="header-anchor" href="#utilitarios-de-performance" aria-label="Permalink to &quot;Utilitarios de Performance&quot;">​</a></h3><p>Para detalhes completos, veja <a href="./utilitarios-performance">Utilitarios de Performance</a>.</p><table tabindex="0"><thead><tr><th>Utilitario</th><th>Engine</th><th>Impacto Estimado</th><th>Status</th></tr></thead><tbody><tr><td>Face Quality (CR-FIQA)</td><td><code>face_quality.py</code></td><td>-30% embeddings inuteis no Milvus</td><td>Ativo</td></tr><tr><td>Image Dedup (multi-hash)</td><td><code>image_dedup.py</code></td><td>-20% processamento redundante</td><td>Ativo</td></tr><tr><td>Anti-Spoofing (dual mode)</td><td><code>face_antispoof.py</code></td><td>Bloqueia uploads fraudulentos</td><td>Ativo (modelo opcional)</td></tr><tr><td>Image Forensics (ELA)</td><td><code>image_forensics.py</code></td><td>Complementa DeepGuard (deepfake)</td><td>Ativo</td></tr><tr><td>AdaFace Benchmark</td><td><code>adaface_embedder.py</code></td><td>Melhor recall em low-quality</td><td>Benchmark (modelo opcional)</td></tr></tbody></table><h3 id="kubexfaceindex" tabindex="-1">KubexFaceIndex <a class="header-anchor" href="#kubexfaceindex" aria-label="Permalink to &quot;KubexFaceIndex&quot;">​</a></h3><p>O KubexFaceIndex e um banco proprietario de embeddings faciais que cresce organicamente durante crawls de todos os motores. Nao e um motor em si, mas uma camada de enriquecimento que alimenta a busca facial web.</p><table tabindex="0"><thead><tr><th>Componente</th><th>Implementacao</th><th>Detalhes</th></tr></thead><tbody><tr><td>Collection Milvus</td><td><code>kubex_web_faces</code></td><td>512-dim HNSW COSINE, 7 particoes por categoria</td></tr><tr><td>OptOut Collection</td><td><code>kubex_face_optouts</code></td><td>Embeddings de faces que nao devem ser re-indexadas</td></tr><tr><td>Ingestao</td><td><code>face_index_ingest.py</code></td><td>Tiered dedup (3 tiers: &gt;0.95 duplicata, 0.85-0.95 mesma pessoa, &lt;0.85 nova face)</td></tr><tr><td>Busca usuario</td><td><code>POST /face-search/web</code></td><td>Plan-gated (Pro/Premium), requer consentimento LGPD</td></tr><tr><td>Busca unificada</td><td><code>POST /face-search/web/unified</code></td><td>Usa embedding armazenado ou selfie avulsa</td></tr><tr><td>Unlock</td><td><code>POST /face-search/web/unlock</code></td><td>Desbloqueia URLs completas (Pro gasta credito, Premium incluso)</td></tr><tr><td>Thumbnails</td><td>R2 <code>faces/{YYYY-MM}/{uuid}.jpg</code></td><td>Face crops 150px JPEG, presigned URLs 1h</td></tr><tr><td>Anti-stalking</td><td><code>FaceSearchLog</code></td><td>pHash de queries + IP para auditoria forense (retencao 90 dias)</td></tr><tr><td>Admin</td><td>8 endpoints</td><td>Stats, health, top-domains, force-stats, force-dedup, opt-out CRUD</td></tr><tr><td>NCII (D2)</td><td>7 endpoints usuario</td><td>Alertas, consent LGPD, takedown, Kit B.O. PDF</td></tr></tbody></table><hr><h2 id="celery-beat-schedule-40-tasks" tabindex="-1">Celery Beat Schedule (40 tasks) <a class="header-anchor" href="#celery-beat-schedule-40-tasks" aria-label="Permalink to &quot;Celery Beat Schedule (40 tasks)&quot;">​</a></h2><h3 id="monitoramento" tabindex="-1">Monitoramento <a class="header-anchor" href="#monitoramento" aria-label="Permalink to &quot;Monitoramento&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Motor</th></tr></thead><tbody><tr><td><code>trigger_telegram_scan</code></td><td>10 min</td><td>Telegram</td></tr><tr><td><code>trigger_discord_scan</code></td><td>10 min</td><td>Discord</td></tr><tr><td><code>trigger_reddit_scan</code></td><td>30 min</td><td>Reddit</td></tr><tr><td><code>trigger_google_alerts_scan</code></td><td>1 hora</td><td>AlertsFeed</td></tr><tr><td><code>trigger_crawler_scans</code></td><td>1 hora</td><td>Crawler</td></tr><tr><td><code>trigger_twitter_scan</code></td><td>2 horas</td><td>X Monitor</td></tr><tr><td><code>trigger_instagram_scan</code></td><td>3 horas</td><td>Instagram</td></tr><tr><td><code>trigger_name_monitoring</code></td><td>6 horas</td><td>BrandWatch</td></tr><tr><td><code>trigger_facebook_scan</code></td><td>6 horas</td><td>Facebook</td></tr><tr><td><code>trigger_adult_crawler</code></td><td>6 horas</td><td>ShieldAI</td></tr><tr><td><code>trigger_flickr_scan</code></td><td>12 horas</td><td>Flickr</td></tr><tr><td><code>trigger_image_rescan</code></td><td>diario 03:17</td><td>Lens</td></tr><tr><td><code>trigger_darkweb_scan</code></td><td>diario 04:23</td><td>DarkWeb</td></tr><tr><td><code>trigger_marketplace_scan</code></td><td>diario 05:11</td><td>Marketplace</td></tr><tr><td><code>trigger_instagram_discovery</code></td><td>6 dias</td><td>Instagram</td></tr><tr><td><code>sentinel_watchdog</code></td><td>5 min</td><td>Sentinel</td></tr></tbody></table><h3 id="discovery-sourceintel" tabindex="-1">Discovery &amp; SourceIntel <a class="header-anchor" href="#discovery-sourceintel" aria-label="Permalink to &quot;Discovery &amp; SourceIntel&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Componente</th></tr></thead><tbody><tr><td><code>feed_approved_targets</code></td><td>30 min</td><td>Discovery Feed</td></tr><tr><td><code>score_pending_targets</code></td><td>1 hora</td><td>Discovery Scoring</td></tr><tr><td><code>run_dork_spider</code></td><td>6 horas</td><td>DorkSpider</td></tr><tr><td><code>trigger_discovery_scan</code></td><td>12 horas</td><td>SourceIntel</td></tr><tr><td><code>map_telegram_network</code></td><td>diario 05:37</td><td>Telepathy</td></tr><tr><td><code>health_check_sources</code></td><td>diario 06:03</td><td>SourceIntel</td></tr><tr><td><code>recalculate_feedback_scores</code></td><td>diario 06:29</td><td>Discovery Feedback</td></tr><tr><td><code>resurrect_dead_sources</code></td><td>7 dias</td><td>Discovery</td></tr></tbody></table><h3 id="face-index" tabindex="-1">Face Index <a class="header-anchor" href="#face-index" aria-label="Permalink to &quot;Face Index&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Componente</th></tr></thead><tbody><tr><td><code>cleanup_orphan_selfies</code></td><td>10 min</td><td>Face Worker (LGPD)</td></tr><tr><td><code>refresh_optout_cache</code></td><td>1 hora</td><td>OptOut Cache</td></tr><tr><td><code>daily_stats</code></td><td>diario 03:43</td><td>KubexFaceIndex</td></tr><tr><td><code>cleanup_search_logs</code></td><td>diario 04:07</td><td>KubexFaceIndex (LGPD)</td></tr><tr><td><code>verify_urls</code></td><td>7 dias</td><td>KubexFaceIndex</td></tr><tr><td><code>cleanup_dead</code></td><td>30 dias</td><td>KubexFaceIndex</td></tr></tbody></table><h3 id="manutencao-lgpd" tabindex="-1">Manutencao &amp; LGPD <a class="header-anchor" href="#manutencao-lgpd" aria-label="Permalink to &quot;Manutencao &amp; LGPD&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Componente</th></tr></thead><tbody><tr><td><code>cleanup_stale_jobs</code></td><td>30 min</td><td>Jobs</td></tr><tr><td><code>check_pending_verifications</code></td><td>1 hora</td><td>Takedown</td></tr><tr><td><code>process_auto_takedowns</code></td><td>1 hora</td><td>Takedown</td></tr><tr><td><code>cleanup_old_temp_files</code></td><td>1 hora</td><td>Storage</td></tr><tr><td><code>check_expired_subscriptions</code></td><td>1 hora</td><td>Pagamentos</td></tr><tr><td><code>bulk_crawl_batch</code></td><td>1 hora</td><td>Bulk Crawling</td></tr><tr><td><code>cleanup_old_search_results</code></td><td>diario 02:07</td><td>Limpeza</td></tr><tr><td><code>cleanup_engine_activity_logs</code></td><td>diario 02:31</td><td>Limpeza</td></tr><tr><td><code>cleanup_expired_evidence</code></td><td>diario 02:47</td><td>LGPD</td></tr><tr><td><code>cleanup_old_audit_logs</code></td><td>diario 03:03</td><td>LGPD</td></tr><tr><td><code>kaas_memory_lifecycle</code></td><td>diario 03:33</td><td>KAAS / ChromaDB</td></tr></tbody></table><p>Para detalhes completos, veja <a href="/takedown-docs/arquitetura/automation-resilience">Automacao e Resiliencia</a>.</p><hr><h2 id="benchmark-tecnico-vps-4-vcpu-8gb-ram" tabindex="-1">Benchmark Tecnico (VPS 4 vCPU, 8GB RAM) <a class="header-anchor" href="#benchmark-tecnico-vps-4-vcpu-8gb-ram" aria-label="Permalink to &quot;Benchmark Tecnico (VPS 4 vCPU, 8GB RAM)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operacao</th><th>Tempo medio</th><th>Throughput/hora</th></tr></thead><tbody><tr><td>pHash de 1 imagem</td><td>~50ms</td><td>~72.000</td></tr><tr><td>compare_batch() 1k hashes (numpy)</td><td>&lt;100ms</td><td>—</td></tr><tr><td>Face detection + embedding 512D (InsightFace CPU)</td><td>~300ms</td><td>~12.000</td></tr><tr><td>Face search Milvus HNSW (1k embeddings)</td><td>~2ms</td><td>—</td></tr><tr><td>Face search Milvus HNSW (100k embeddings)</td><td>~10ms</td><td>—</td></tr><tr><td>Crawl + download de 1 pagina (Fetcher)</td><td>~1-3s</td><td>~1.200-3.600</td></tr><tr><td>Crawl + download de 1 pagina (StealthyFetcher)</td><td>~3-8s</td><td>~450-1.200</td></tr><tr><td>OCR Tesseract 1 imagem (por+eng)</td><td>~200ms</td><td>~18.000</td></tr><tr><td>Deepfake DCT analysis</td><td>~50ms</td><td>~72.000</td></tr><tr><td>Deepfake EfficientNet (GPU)</td><td>~200ms</td><td>~18.000</td></tr><tr><td>Proxy /proxy/image (sanitize + resize 400px)</td><td>~80ms</td><td>~45.000</td></tr></tbody></table><p><strong>Nota:</strong> StealthyFetcher e mais lento por usar browser real com bypass de anti-bot. Usar apenas quando necessario (Cloudflare). Para sites simples, Fetcher e ~3x mais rapido.</p><p>VPS 4 vCPU processa ~5.000 imagens/hora com deteccao facial. Suficiente para ate ~500 usuarios ativos com monitoramento diario.</p>',29)])])}const p=d(o,[["render",i]]);export{u as __pageData,p as default};
